import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
// Import all your page components
import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
  return (
    <Router>
      <Navbar /> {/* This displays the navigation links */}
      <div className="container" style={{ maxWidth: '1200px', margin: '20px auto', padding: '0 15px' }}>
        <Routes>
          {/* Default landing page */}
          <Route path="/" element={<h1>Welcome to the Waste Management System Dashboard</h1>} />
          
          {/* Routes for each entity management page */}
          <Route path="/authority" element={<AuthorityPage />} />
          <Route path="/bin" element={<BinPage />} />
          <Route path="/driver" element={<DriverPage />} />
          <Route path="/user" element={<UserPage />} />
          <Route path="/vehicle" element={<VehiclePage />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
